ee:message.ee:set-payload:
%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{ jsonrpc: "2.0", id: vars.rpcId, result: { content: [{ "type": "text", text: write(resultBody, "application/json") }], isError: isError } }

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "lookup_incident",
      description: "incidentId で既存 Incident__c を 1 件取得する。404 のときは exists=false を返す。",
      inputSchema: {
        "type": "object",
        properties: { incidentId: { "type": "string" } },
        required: ["incidentId"]
      }
    },
    {
      name: "register_incident",
      description: "Incident__c を新規作成する。incidentId 未指定なら incident-system が採番。",
      inputSchema: {
        "type": "object",
        properties: {
          incidentId:       { "type": "string" },
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          quantity:         { "type": "integer" },
          severity:         { "type": "string", "enum": ["LOW", "MEDIUM", "HIGH", "CRITICAL"] },
          rawMessage:       { "type": "string" },
          slackChannel:     { "type": "string" },
          slackThreadTs:    { "type": "string" }
        },
        required: ["supplierGoldenId", "partNumber", "severity", "rawMessage"]
      }
    },
    {
      name: "update_incident_status",
      description: "incidentId のステータスを更新する。OPEN / IN_PROGRESS / RESOLVED。",
      inputSchema: {
        "type": "object",
        properties: {
          incidentId: { "type": "string" },
          "status":   { "type": "string", "enum": ["OPEN", "IN_PROGRESS", "RESOLVED"] }
        },
        required: ["incidentId", "status"]
      }
    }
  ]
}

