ee:variables.ee:set-variable:
%dw 2.0
output application/java
fun safeReadJson(s) = if (s == null or trim(s) == "") {} else read(s, "application/json")
---
if (payload == null) {}
else if (payload is Binary) safeReadJson(payload as String { encoding: "UTF-8" })
else if (payload is String) safeReadJson(payload)
else payload

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
if ((vars.status default 0) >= 200 and (vars.status default 0) < 300)
  { status: "success", tool: vars.toolName, result: { exists: true, incident: vars.bodyObj } }
else if ((vars.status default 0) == 404)
  { status: "success", tool: vars.toolName, result: { exists: false, incidentId: vars.incidentId default "" } }
else
  { status: "error", tool: vars.toolName, result: { code: "BACKEND_ERROR", httpStatus: vars.status, body: vars.bodyObj } }

