ee:message.ee:set-payload:
%dw 2.0
output application/json
---
if ((vars.status default 0) >= 200 and (vars.status default 0) < 300)
  { status: "success", tool: vars.toolName, result: ((vars.bodyObj default {}) ++ { "status": "CREATED" }) }
else if ((vars.status default 0) == 409 and ((vars.bodyObj.code default "") as String) == "ALREADY_EXISTS")
  { status: "success", tool: vars.toolName, result: { "status": "EXISTS", incidentId: ((vars.bodyObj.incidentId default "") as String), supplierGoldenId: ((vars.toolInput.supplierGoldenId default "") as String), partNumber: ((vars.toolInput.partNumber default "") as String), severity: ((vars.toolInput.severity default "") as String), rawMessage: ((vars.toolInput.rawMessage default "") as String) } }
else
  { status: "error", tool: vars.toolName, result: { "status": "ERROR", code: ((vars.bodyObj.code default "BACKEND_ERROR") as String), httpStatus: vars.status, message: ((vars.bodyObj.message default "incident-system returned non-2xx") as String), body: vars.bodyObj } }

ee:variables.ee:set-variable:
